# ---------------------------------------------------------------------------
# Sensitive Data Redaction
# ---------------------------------------------------------------------------

SENSITIVE_FIELDS = {
    "password", "passwd", "secret", "token", "authorization",
    "access_token", "refresh_token", "api_key", "apikey",
    "credit_card", "card_number", "cvv", "ssn", "social_security",
    "private_key", "session_id", "cookie",
}

SENSITIVE_HEADER_KEYS = {"authorization", "cookie", "x-api-key", "x-auth-token"}

REDACTED = "***REDACTED***"


def redact_sensitive_data(data, depth=0):
    """Recursively redact sensitive fields from dicts/lists."""
    if depth > 10:
        return data
    if isinstance(data, dict):
        redacted = {}
        for key, value in data.items():
            if key.lower() in SENSITIVE_FIELDS:
                redacted[key] = REDACTED
            else:
                redacted[key] = redact_sensitive_data(value, depth + 1)
        return redacted
    elif isinstance(data, list):
        return [redact_sensitive_data(item, depth + 1) for item in data]
    elif isinstance(data, str):
        # Redact patterns that look like tokens (Bearer <token>, JWT, etc.)
        text = re.sub(
            r'(Bearer\s+)\S+', r'\1' + REDACTED, data
        )
        text = re.sub(
            r'(eyJ[A-Za-z0-9_-]+\.eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+)',
            REDACTED, text
        )
        return text
    return data


def redact_headers(headers):
    """Redact sensitive headers while preserving non-sensitive ones."""
    safe_headers = {}
    for key, value in headers:
        if key.lower() in SENSITIVE_HEADER_KEYS:
            # Show type of auth but not the credential itself
            if key.lower() == "authorization" and value:
                scheme = value.split(" ")[0] if " " in value else "unknown-scheme"
                safe_headers[key] = f"{scheme} {REDACTED}"
            else:
                safe_headers[key] = REDACTED
        else:
            safe_headers[key] = value
    return safe_headers


# ---------------------------------------------------------------------------
# Custom Log Formatter
# ---------------------------------------------------------------------------

class RequestFormatter(logging.Formatter):
    """Formatter that includes request context information when available."""

    def format(self, record):
        if has_request_context():
            record.url = request.url
            record.method = request.method
            record.remote_addr = request.remote_addr
            record.request_id = getattr(g, "request_id", "N/A")
            record.user_id = getattr(g, "user_id", "anonymous")
        else:
            record.url = "N/A"
            record.method = "N/A"
            record.remote_addr = "N/A"
            record.request_id = "N/A"
            record.user_id = "N/A"
        return super().format(record)


# ---------------------------------------------------------------------------
# Logging Setup
# ---------------------------------------------------------------------------

def setup_logging(app):
    """Configure application logging with file and console handlers."""

    log_format = (
        "[%(asctime)s] %(levelname)s | req=%(request_id)s | "
        "user=%(user_id)s | %(remote_addr)s %(method)s %(url)s | "
        "%(module)s:%(funcName)s:%(lineno)d | %(message)s"
    )
    formatter = RequestFormatter(log_format)

    # Console handler
    console_handler = logging.StreamHandler()
    console_handler.setFormatter(formatter)
    console_handler.setLevel(logging.DEBUG)

    # Rotating file handler – general logs
    os.makedirs("logs", exist_ok=True)
    file_handler = RotatingFileHandler(
        "logs/app.log", maxBytes=10_000_000, backupCount=10
    )
    file_handler.setFormatter(formatter)
    file_handler.setLevel(logging.INFO)

    # Error-only file handler
    error_handler = RotatingFileHandler(
        "logs/error.log", maxBytes=10_000_000, backupCount=10
    )
    error_handler.setFormatter(formatter)
    error_handler.setLevel(logging.ERROR)

    # Audit log for authentication events
    audit_handler = RotatingFileHandler(
        "logs/audit.log", maxBytes=10_000_000, backupCount=10
    )
    audit_handler.setFormatter(formatter)
    audit_handler.setLevel(logging.INFO)

    app.logger.handlers.clear()
    app.logger.addHandler(console_handler)
    app.logger.addHandler(file_handler)
    app.logger.addHandler(error_handler)
    app.logger.setLevel(logging.DEBUG)

    # Separate audit logger
    audit_logger = logging.getLogger("audit")
    audit_logger.handlers.clear()
    audit_logger.addHandler(audit_handler)
    audit_logger.addHandler(console_handler)
    audit_logger.setLevel(logging.INFO)

    return app.logger, audit_logger


