@app.before_request
def before_request_logging():
    """Log every incoming request with safe redaction of sensitive data."""
    g.request_id = str(uuid.uuid4())[:8]
    g.request_start_time = time.time()
    g.user_id = "anonymous"  # Will be updated by auth

    safe_headers = redact_headers(request.headers)

    # Safely capture body
    body = None
    if request.content_type and "json" in request.content_type:
        try:
            body = redact_sensitive_data(request.get_json(silent=True))
        except Exception:
            body = "<unable to parse JSON>"
    elif request.form:
        body = redact_sensitive_data(dict(request.form))
    else:
        content_length = request.content_length or 0
        if content_length > 0:
            body = f"<binary or non-JSON body, {content_length} bytes>"

    logger.info(
        "REQUEST RECEIVED | headers=%s | query=%s | body=%s",
        json.dumps(safe_headers, default=str),
        redact_sensitive_data(dict(request.args)),
        json.dumps(body, default=str) if body else "None",
    )


@app.after_request
def after_request_logging(response):
    """Log every outgoing response with timing information."""
    duration_ms = (time.time() - g.get("request_start_time", time.time())) * 1000

    # Log response body for non-binary content (truncated)
    response_body = None
    if response.content_type and "json" in response.content_type:
        try:
            resp_data = response.get_json(silent=True)
            response_body = redact_sensitive_data(resp_data)
        except Exception:
            response_body = "<unable to parse response JSON>"

    log_level = logging.WARNING if response.status_code >= 400 else logging.INFO

    logger.log(
        log_level,
        "RESPONSE SENT | status=%s | duration=%.2fms | size=%s | body=%s",
        response.status_code,
        duration_ms,
        response.content_length,
        json.dumps(response_body, default=str)[:500] if response_body else "N/A",
    )

    # Add request ID to response headers for traceability
    response.headers["X-Request-ID"] = g.get("request_id", "unknown")
    return response


@app.errorhandler(Exception)
def handle_exception(e):
    """Catch-all error handler that logs full exception details."""
    logger.exception(
        "UNHANDLED EXCEPTION | type=%s | message=%s",
        type(e).__name__,
        str(e),
    )
    return jsonify({
        "error": "Internal server error",
        "request_id": g.get("request_id", "unknown"),
    }), 500


@app.errorhandler(404)
def not_found(e):
    logger.warning("ROUTE NOT FOUND | path=%s", request.path)
    return jsonify({"error": "Not found"}), 404


@app.errorhandler(405)
def method_not_allowed(e):
    logger.warning(
        "METHOD NOT ALLOWED | path=%s | method=%s", request.path, request.method
    )
    return jsonify({"error": "Method not allowed"}), 405


