def require_auth(f):
    """Simple decorator that checks for a Bearer token (demo only)."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            logger.warning("AUTH FAILED | reason=missing_or_invalid_bearer_token")
            return jsonify({"error": "Unauthorized"}), 401

        token = auth_header.split(" ", 1)[1]
        # In production: validate JWT / session token properly
        user = _validate_token(token)
        if not user:
            # Log the failure but NEVER the token itself
            audit_logger.warning(
                "AUTH FAILED | reason=invalid_token | "
                "token_prefix=%s... | ip=%s",
                token[:4] if len(token) >= 4 else "????",
                request.remote_addr,
            )
            return jsonify({"error": "Unauthorized"}), 401

        g.user_id = user["user_id"]
        logger.info("AUTH SUCCESS | user_id=%s | role=%s", user["user_id"], user["role"])
        return f(*args, **kwargs)
    return decorated


def _validate_token(token):
    """Demo token validator. Replace with real JWT validation."""
    # For demo: accept "valid-token-<username>"
    if token.startswith("valid-token-"):
        username = token.replace("valid-token-", "")
        return USERS_DB.get(username)
    return None


