@app.route("/api/login", methods=["POST"])
def login():
    """
    Login endpoint. Logs the *attempt* (username, IP, result) but
    NEVER logs the password.
    """
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    # password is intentionally NOT logged
    password = data.get("password", "")

    audit_logger.info(
        "LOGIN ATTEMPT | username=%s | ip=%s | user_agent=%s",
        username,
        request.remote_addr,
        request.user_agent.string[:100],
    )

    user = USERS_DB.get(username)
    if not user:
        audit_logger.warning(
            "LOGIN FAILED | reason=user_not_found | username=%s | ip=%s",
            username,
            request.remote_addr,
        )
        return jsonify({"error": "Invalid credentials"}), 401

    # Demo password check (use bcrypt.checkpw in production)
    if password != "demo_password":
        audit_logger.warning(
            "LOGIN FAILED | reason=bad_password | username=%s | ip=%s",
            username,
            request.remote_addr,
        )
        return jsonify({"error": "Invalid credentials"}), 401

    # In production: generate a signed JWT here
    token = f"valid-token-{username}"

    audit_logger.info(
        "LOGIN SUCCESS | username=%s | user_id=%s | ip=%s",
        username,
        user["user_id"],
        request.remote_addr,
    )

    g.user_id = user["user_id"]
    return jsonify({
        "message": "Login successful",
        "token": token,  # The response will be redacted in logs automatically
        "user_id": user["user_id"],
    })


